import { useEffect, useMemo, useState, type RefObject } from 'react'

type WindowRange = {
  start: number
  end: number
}

type UseListWindowingOptions = {
  enabled: boolean
  itemCount: number
  containerRef: RefObject<HTMLElement | null>
  mode?: 'container' | 'window'
  rowHeight?: number
  overscan?: number
  minWindowItems?: number
  threshold?: number
}

type ListWindowingResult = {
  isActive: boolean
  startIndex: number
  endIndex: number
  topSpacerHeight: number
  bottomSpacerHeight: number
}

const clamp = (value: number, min: number, max: number) => Math.min(Math.max(value, min), max)

export const useListWindowing = ({
  enabled,
  itemCount,
  containerRef,
  mode = 'container',
  rowHeight = 120,
  overscan = 12,
  minWindowItems = 90,
  threshold = 180
}: UseListWindowingOptions): ListWindowingResult => {
  const isActive = enabled && itemCount >= threshold

  const [range, setRange] = useState<WindowRange>({ start: 0, end: itemCount })

  useEffect(() => {
    if (!isActive) {
      setRange({ start: 0, end: itemCount })
      return
    }

    const initialEnd = Math.min(itemCount, Math.max(1, minWindowItems))
    setRange({ start: 0, end: initialEnd })
  }, [isActive, itemCount, minWindowItems])

  useEffect(() => {
    if (!isActive) return

    const container = containerRef.current
    if (!container) return

    let rafId: number | null = null

    const calculateRange = () => {
      const viewportHeight =
        mode === 'window'
          ? (window.innerHeight || rowHeight * 8)
          : (container.clientHeight || rowHeight * 8)
      const itemsPerViewport = Math.max(1, Math.ceil(viewportHeight / rowHeight))
      const desiredWindowSize = Math.max(minWindowItems, itemsPerViewport + overscan * 2)
      const maxStart = Math.max(0, itemCount - desiredWindowSize)

      const scrollTop = (() => {
        if (mode !== 'window') {
          return container.scrollTop
        }

        const scrollY =
          window.scrollY ||
          window.pageYOffset ||
          document.documentElement.scrollTop ||
          0
        const listTop = container.getBoundingClientRect().top + scrollY
        return scrollY - listTop
      })()

      const rawStart = Math.floor(scrollTop / rowHeight) - overscan
      const nextStart = clamp(rawStart, 0, maxStart)
      const nextEnd = clamp(nextStart + desiredWindowSize, 0, itemCount)

      setRange((prev) => {
        if (prev.start === nextStart && prev.end === nextEnd) {
          return prev
        }

        return { start: nextStart, end: nextEnd }
      })
    }

    const onScrollOrResize = () => {
      if (rafId !== null) return

      rafId = window.requestAnimationFrame(() => {
        rafId = null
        calculateRange()
      })
    }

    calculateRange()

    if (mode === 'window') {
      window.addEventListener('scroll', onScrollOrResize, { passive: true })
    } else {
      container.addEventListener('scroll', onScrollOrResize, { passive: true })
    }
    window.addEventListener('resize', onScrollOrResize)

    return () => {
      if (mode === 'window') {
        window.removeEventListener('scroll', onScrollOrResize)
      } else {
        container.removeEventListener('scroll', onScrollOrResize)
      }
      window.removeEventListener('resize', onScrollOrResize)
      if (rafId !== null) {
        window.cancelAnimationFrame(rafId)
      }
    }
  }, [isActive, itemCount, containerRef, mode, rowHeight, overscan, minWindowItems])

  return useMemo(() => {
    if (!isActive) {
      return {
        isActive: false,
        startIndex: 0,
        endIndex: itemCount,
        topSpacerHeight: 0,
        bottomSpacerHeight: 0
      }
    }

    const safeStart = clamp(range.start, 0, itemCount)
    const safeEnd = clamp(Math.max(range.end, safeStart), 0, itemCount)

    return {
      isActive: true,
      startIndex: safeStart,
      endIndex: safeEnd,
      topSpacerHeight: safeStart * rowHeight,
      bottomSpacerHeight: Math.max(0, (itemCount - safeEnd) * rowHeight)
    }
  }, [isActive, itemCount, range.start, range.end, rowHeight])
}
